import React, { useEffect, useRef } from 'react';
import { Linking } from 'react-native';
import { useNavigation } from '@react-navigation/native';

const DeepLinkHandler = () => {
  const navigation = useNavigation();
  const initialUrlChecked = useRef(false);

  useEffect(() => {
    // Function to handle a received URL
    const handleDeepLink = (url) => {
      if (!url) return;

      const [scheme, path] = url.split('://');
      if (scheme !== 'myapp') {
        // Not our app's scheme
        return;
      }

      const pathParts = path.split('/');
      const screenName = pathParts[0]; // e.g., 'profile', 'payment'
      const paramId = pathParts[1]; // e.g., '123', 'confirm'

      switch (screenName) {
        case 'profile':
          if (paramId) {
            navigation.navigate('ProfileScreen', { userId: paramId });
          } else {
            navigation.navigate('ProfileScreen');
          }
          break;
        case 'payment':
          if (paramId === 'confirm') {
            navigation.navigate('PaymentConfirmationScreen');
          } else {
            // Handle other payment related paths or default
            navigation.navigate('PaymentScreen');
          }
          break;
        // Add more cases for other deep link paths
        default:
          // Navigate to a default screen or handle unknown paths
          navigation.navigate('HomeScreen');
          break;
      }
    };

    // 1. Handle initial deep link when the app is launched from a URL
    if (!initialUrlChecked.current) {
      Linking.getInitialURL().then(url => {
        if (url) {
          handleDeepLink(url);
        }
      });
      initialUrlChecked.current = true;
    }


    // 2. Handle deep links when the app is already running in the background
    const subscription = Linking.addEventListener('url', ({ url }) => {
      handleDeepLink(url);
    });

    // Clean up the event listener when the component unmounts
    return () => {
      subscription.remove();
    };
  }, [navigation]);

  return null; // This component doesn't render anything, it just handles deep links
};

export default DeepLinkHandler;

